const PILLARS = ['gastroenterologia','endoscopia','colonoscopia','hepatologia','geriatria'];
const POSTS_PER_RUN = 6;

// Sub-temas rankeados por prioridade SEO (5=ancora-quick-win, 4=high, 3=mid, 2=long-tail)
// Order matters: picker prefere top da lista entre os ainda nao usados
const SUBTOPICS = {
  'gastroenterologia': [
    'gastroenterologista-recife','refluxo-gastroesofagico-sintomas-tratamento','quando-procurar-gastroenterologista','gastrite-sintomas-tratamento',
    'helicobacter-pylori-tratamento','consulta-gastro-particular-recife','intestino-irritavel-sii-sintomas','dor-de-barriga-quando-procurar-medico','azia-queimacao-causa','intolerancia-a-lactose-teste',
