const inp = $('Ler Settings + Buffer').first().json;
const last = inp.last_pillar || 'none';
const recent = Array.isArray(inp.recent_topics) ? inp.recent_topics : [];
const startIdx = (PILLARS.indexOf(last) + 1) % PILLARS.length;
const picks = Array.from({length: POSTS_PER_RUN}, (_, i) => PILLARS[(startIdx + i) % PILLARS.length]);

// === ANTI-REPETICAO FORTE ===
// tema-chave = 2 primeiros tokens do slug (ex: 'esteatose-hepatica-grau-1-2-3' -> 'esteatose-hepatica').
// Um tema-chave so volta quando o pool de temas ineditos do pilar esgotar.
function themeKey(slug) {
  return String(slug || '').toLowerCase().split('-').slice(0, 2).join('-');
}
const recentThemesByPillar = {};
recent.forEach(r => {
  if (!r || !r.pillar) return;
  if (!recentThemesByPillar[r.pillar]) recentThemesByPillar[r.pillar] = new Set();
  recentThemesByPillar[r.pillar].add(themeKey(r.slug));
});
const usedInBatch = new Set();
const usedThemesInBatch = new Set();

function pickSubtopic(pillar) {
  const pool = SUBTOPICS[pillar] || [];
  const recentThemes = recentThemesByPillar[pillar] || new Set();
  let candidates = pool.filter(st => !usedInBatch.has(st)
    && !recentThemes.has(themeKey(st))
    && !usedThemesInBatch.has(themeKey(st)));
  if (candidates.length === 0) {
    candidates = pool.filter(st => !usedInBatch.has(st));
  }
  if (candidates.length === 0) candidates = pool;
  const chosen = candidates[Math.floor(Math.random() * candidates.length)] || 'saude-digestiva';
  usedInBatch.add(chosen);
  usedThemesInBatch.add(themeKey(chosen));
  return chosen;
}

// === SUGESTOES DA EQUIPE (furam a fila; FIFO por pilar) ===
const sugRows = $('SELECT Sugestoes').all().map(i => i.json).filter(r => r && r.id && r.topic_text);
const sugByPillar = {};
sugRows.forEach(s => { (sugByPillar[s.pillar] = sugByPillar[s.pillar] || []).push(s); });

function slugify(t) {
  return String(t).toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60);
}

// === APRENDIZADO: regras (system) + exemplos (user) ===
const ruleRows = $('SELECT Regras Ativas').all().map(i => i.json).filter(r => r && r.rule_text);
const exampleRows = $('SELECT Exemplos').all().map(i => i.json).filter(r => r && r.content_json);

function selectExamples(rows, pillar, n) {
  const same = rows.filter(r => r.pillar === pillar);
  const other = rows.filter(r => r.pillar !== pillar);
  return same.concat(other).slice(0, n);
}
function buildExamplesBlock(examples) {
  if (!examples || examples.length === 0) return '';
  const blocks = examples.map((e, i) => '### Exemplo ' + (i+1) + ': ' + e.title + '\n' + JSON.stringify(e.content_json)).join('\n\n');
  return '\n\nEXEMPLOS DE POSTS APROVADOS — escreva no MESMO estilo, tom e estrutura destes (NAO copie o tema, copie o jeito de escrever):\n\n' + blocks + '\n\n';
}
function buildRulesBlock(rules) {
  if (!rules || rules.length === 0) return '';
  const lines = rules.map(r => '- [' + (r.scope || 'outro') + '] ' + r.rule_text).join('\n');
  return '\n\nREGRAS APRENDIDAS COM O EDITOR (seguir A RISCA, prevalecem sobre o estilo padrao):\n' + lines;
}

const SYSTEM = 'Voce e um redator medico brasileiro especializado em gastroenterologia, endoscopia digestiva, colonoscopia, hepatologia e geriatria. Escreve para pacientes leigos em PT-BR claro, com revisao CFM. SEMPRE emite o resultado chamando a ferramenta emit_post (objeto BlogPost estruturado, sem texto fora da ferramenta). Inclui ao menos 3 H2, ao menos 1500 palavras, FAQ com 4-6 perguntas, autoria Dra. Jane Erika Frazao Okazaki (CRM-PE 19872, RQE 17633). Sem promessas de cura, sem before-after, sem testimonials.';
const SYSTEM_FINAL = SYSTEM + buildRulesBlock(ruleRows);

function userPrompt(pillar, subtopic, topicText) {
  const foco = topicText
    ? 'FOCO OBRIGATORIO E EXCLUSIVO (tema sugerido pela equipe da clinica — atenda exatamente este pedido): "' + topicText + '". '
    : 'FOCO OBRIGATORIO E EXCLUSIVO: sub-tema "' + subtopic + '". ';
  return 'Gere um rascunho de post de blog medico para a Clinica Okazaki sobre o pilar ' + pillar + '.\n\n' +
    foco +
    'O slug DEVE comecar com "' + subtopic + '" (pode adicionar palavras adicionais depois com hifen, ou usar o slug exato). ' +
    'O titulo, lead, sections, faqs e todo o conteudo devem girar exclusivamente em torno deste sub-tema. NAO escreva post generico sobre ' + pillar + ' inteiro. ' +
    'NAO repita angulos batidos: aborde com profundidade clinica especifica (sintomas, diagnostico, exames, conduta, criterios, evidencias) e quando aplicavel inclua geo-modifier "Recife" no description e/ou title.\n\n' +
    'Emita via ferramenta emit_post um objeto com este shape: { slug, pillar, title, description (140-160 chars com geo-modifier em Recife quando faz sentido), keywords, h1, lead, eyebrow (BLOG dot ' + pillar.toUpperCase() + '), breadcrumbLabel, about, excerpt (80-200 chars), sections (array com id slug-style, h2, blocks), faqs (array {q,a}), author (Dra. Jane Erika Frazao Okazaki, CRM-PE 19872, RQE 17633, photo /assets/team/jane.webp, bio), publishedAt ISO, updatedAt ISO }. Block types: p, h3, ul (items array), callout, warning, inline-cta, link. Total 1500-2000 palavras em 4-6 sections. Inclua ao menos 1 link interno para /' + pillar + '.';
}

return picks.map(pillar => {
  const sug = (sugByPillar[pillar] || []).shift();
  const subtopic = sug ? slugify(sug.topic_text) : pickSubtopic(pillar);
  if (sug) { usedInBatch.add(subtopic); usedThemesInBatch.add(themeKey(subtopic)); }
  const examples = selectExamples(exampleRows, pillar, 3);
  return { json: {
    pillar,
    subtopic,
    suggestion_id: sug ? sug.id : null,
    suggested_topic: sug ? sug.topic_text : null,
    system: SYSTEM_FINAL,
    user: userPrompt(pillar, subtopic, sug ? sug.topic_text : null) + buildExamplesBlock(examples)
  } };
});

const raw = $input.item.json;
const tu = (raw.content || []).find(c => c.type === 'tool_use');
if (!tu || !tu.input) throw new Error('Anthropic response sem tool_use. stop_reason=' + (raw.stop_reason || '?'));
const parsed = tu.input;
const required = ['slug','pillar','title','description','keywords','h1','lead','eyebrow','breadcrumbLabel','about','excerpt','sections','faqs','author','publishedAt','updatedAt'];
const missing = required.filter(k => !(k in parsed));
if (missing.length) throw new Error('Campos faltando: ' + missing.join(','));
if (!Array.isArray(parsed.sections) || parsed.sections.length === 0) throw new Error('sections vazio');
if (!Array.isArray(parsed.faqs)) throw new Error('faqs deve ser array');
if (!/^[a-z0-9][a-z0-9-]*$/.test(parsed.slug)) throw new Error('slug invalido: ' + parsed.slug);
if (parsed.description.length < 80 || parsed.description.length > 200) throw new Error('description fora de 80-200 chars: ' + parsed.description.length);
const flatText = JSON.stringify(parsed);
const wordCount = flatText.split(/\s+/).length;
const keywordsArr = typeof parsed.keywords === 'string' ? parsed.keywords.split(',').map(k => k.trim()) : parsed.keywords;
return { json: { slug: parsed.slug, pillar: parsed.pillar, title: parsed.title, meta_description: parsed.description, keywords: keywordsArr, content_json: parsed, word_count: wordCount, generated_by: 'claude-sonnet-4-5', status: 'pending_review' } };
